import React from 'react';
import HomeHeader from './home_page/homeHeader.jsx';
import DishePresentationSheet from './home_page/dishePresentationSheet.jsx';

const dishes = [
		{
			id: 1,
			title: 'Spaghetti Carbonara',
			prepTime: '20 min',
			image: '/logo.svg',
			description: "Un plat italien classique à base de pâtes, d'œufs, de fromage et de pancetta.",
			ingredients: [
				'200g de spaghetti',
				'100g de pancetta',
				"2 œufs",
				'50g de parmesan râpé',
				'Sel et poivre'
			],
			steps: ['Faire cuire les pâtes', 'Cuire la pancetta', 'Mélanger les œufs et le fromage', 'Assembler rapidement']
		},
		{
			id: 2,
			title: 'Poulet au curry',
			prepTime: '35 min',
			image: '/logo.svg',
			description: 'Un plat savoureux à base de poulet, de curry et de lait de coco.',
			ingredients: ['500g de poulet', '2 cuillères à soupe de curry en poudre', '400ml de lait de coco', '1 oignon', '2 gousses d\'ail', 'Sel et poivre'],
			steps: ['Faire revenir l\'oignon et l\'ail', 'Ajouter le poulet', 'Ajouter le curry et le lait de coco', 'Laisser mijoter']
		},
		{
			id: 3,
			title: 'Salade César',
			prepTime: '15 min',
			image: '/logo.svg',
			description: 'Une salade fraîche et croquante avec une sauce crémeuse au parmesan.',
			ingredients: ['Laitue romaine', 'Poulet grillé', 'Croûtons', 'Parmesan', 'Sauce César'],
			steps: ['Laver la laitue', 'Griller le poulet', 'Préparer la sauce', 'Assembler la salade']
		},
		{
			id: 4,
			title: 'Tarte aux pommes',
			prepTime: '45 min',
			image: '/logo.svg',
			description: 'Une tarte sucrée et croustillante garnie de pommes caramélisées.',
			ingredients: ['1 pâte brisée', '4 pommes', '50g de sucre', '20g de beurre', '1 cuillère à café de cannelle'],
			steps: ['Préchauffer le four', 'Étaler la pâte', 'Préparer les pommes', 'Cuire la tarte']
		},
		{
			id: 5,
			title: 'Soupe de légumes',
			prepTime: '30 min',
			image: '/logo.svg',
			description: 'Une soupe réconfortante à base de légumes frais et de bouillon savoureux.',
			ingredients: ['Carottes', 'Pommes de terre', 'Poireaux', 'Bouillon de légumes', 'Sel et poivre'],
			steps: ['Couper les légumes', 'Faire revenir les légumes', 'Ajouter le bouillon', 'Laisser mijoter']
		},
		{
			id: 6,
			title: 'Omelette aux champignons',
			prepTime: '10 min',
			image: '/logo.svg',
			description: 'Une omelette moelleuse garnie de champignons sautés.',
			ingredients: ['3 œufs', '100g de champignons', '1 cuillère à soupe de beurre', 'Sel et poivre'],
			steps: ['Faire sauter les champignons', 'Battre les œufs', 'Cuire l\'omelette', 'Ajouter les champignons']
		},
		{
			id: 7,
			title: 'Riz sauté aux légumes',
			prepTime: '25 min',
			image: '/logo.svg',
			description: 'Un plat rapide et savoureux à base de riz, de légumes et de sauce soja.',
			ingredients: ['200g de riz', 'Légumes variés', '2 cuillères à soupe de sauce soja', '1 cuillère à soupe d\'huile', 'Sel et poivre'],
			steps: ['Cuire le riz', 'Faire sauter les légumes', 'Ajouter le riz et la sauce soja', 'Mélanger et servir']
		}
	];

function HomePage() {
    return (
        <div>
            <HomeHeader/>

            <main style={{ display: 'grid', gap: 16, gridTemplateColumns: 'repeat(auto-fit, minmax(260px, 1fr))', marginTop: 20 }}>
				{dishes.map((d) => (
					<DishePresentationSheet
						key={d.id}
						title={d.title}
						prepTime={d.prepTime}
						image={d.image}
						onSelect={() => setSelected(d)}
					/>
				))}
			</main>
        </div>
    );
}

export default HomePage;
